    pname = None
    for p in name_patterns:
        m = p.search(t)
        if m:
            pname = m.group(1)
            break
    forks = None
    for p in fork_patterns:
        m = p.search(t)
        if m:
            forks = m.group(1)
            break
    return pname, forks

