for t in texts[:5000]:
    pname, forks = extract_one(t)
    if pname and forks:
        matches.append({'name':pname,'forks':forks,'text':t[:180]})
        if len(matches)>=10:
            break

print('__RESULT__:')
print(json.dumps({'matches_found': len(matches), 'examples': matches}))

